import React, { useState } from 'react';
import { ShieldCheck, User, Lock, ArrowRight } from 'lucide-react';

interface LoginProps {
  onLogin: (epic: string, pin: string) => void;
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [epic, setEpic] = useState('');
  const [pin, setPin] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (epic.length < 5 || pin.length < 4) {
      setError('Please enter valid EPIC Number and Security PIN');
      return;
    }
    onLogin(epic, pin);
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-4 gradient-bg">
      <div className="bg-white/95 backdrop-blur-sm p-8 rounded-2xl shadow-2xl w-full max-w-md border border-white/20">
        <div className="text-center mb-8">
          <div className="inline-flex items-center justify-center w-20 h-20 bg-orange-100 rounded-full mb-4">
            <ShieldCheck className="text-[#FF9933]" size={40} />
          </div>
          <h2 className="text-3xl font-bold text-gray-800">BharatVote</h2>
          <p className="text-gray-500 mt-2">Secure Voter Authentication</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Voter EPIC Number</label>
            <div className="relative">
              <User className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input
                type="text"
                value={epic}
                onChange={(e) => setEpic(e.target.value.toUpperCase())}
                placeholder="e.g. EPIC1234567"
                className="w-full pl-10 pr-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-[#FF9933] focus:border-transparent outline-none transition-all uppercase"
                required
              />
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Security PIN / OTP</label>
            <div className="relative">
              <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input
                type="password"
                value={pin}
                onChange={(e) => setPin(e.target.value)}
                placeholder="••••"
                maxLength={4}
                className="w-full pl-10 pr-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-[#FF9933] focus:border-transparent outline-none transition-all"
                required
              />
            </div>
          </div>

          {error && <p className="text-red-500 text-xs italic">{error}</p>}

          <button
            type="submit"
            className="w-full bg-[#138808] hover:bg-[#107006] text-white font-bold py-3 rounded-lg flex items-center justify-center space-x-2 transition-all transform hover:scale-[1.02] active:scale-[0.98]"
          >
            <span>Authenticate Securely</span>
            <ArrowRight size={20} />
          </button>
        </form>

        <div className="mt-8 pt-6 border-t border-gray-100">
          <p className="text-center text-xs text-gray-400 uppercase tracking-widest font-semibold mb-4">Verification Methods</p>
          <div className="grid grid-cols-3 gap-4">
            <div className="flex flex-col items-center opacity-40 grayscale hover:grayscale-0 hover:opacity-100 transition-all cursor-not-allowed">
              <div className="w-10 h-10 bg-gray-100 rounded-full flex items-center justify-center mb-1">☝️</div>
              <span className="text-[10px]">Aadhar Bio</span>
            </div>
            <div className="flex flex-col items-center opacity-40 grayscale hover:grayscale-0 hover:opacity-100 transition-all cursor-not-allowed">
              <div className="w-10 h-10 bg-gray-100 rounded-full flex items-center justify-center mb-1">📷</div>
              <span className="text-[10px]">Face ID</span>
            </div>
             <div className="flex flex-col items-center opacity-100 text-[#138808]">
              <div className="w-10 h-10 bg-green-50 rounded-full flex items-center justify-center mb-1">📱</div>
              <span className="text-[10px]">OTP Sync</span>
            </div>
          </div>
        </div>

        <p className="mt-8 text-center text-[10px] text-gray-400">
          Encrypted with 256-bit AES protocol. Your vote is your power.
        </p>
      </div>
    </div>
  );
};

export default Login;

import React, { useState } from 'react';
import { Candidate } from '../types';
import { CheckCircle2, AlertCircle } from 'lucide-react';

interface VotingBallotProps {
  candidates: Candidate[];
  onVote: (candidateId: string) => void;
  voterConstituency: string;
}

const VotingBallot: React.FC<VotingBallotProps> = ({ candidates, onVote, voterConstituency }) => {
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isConfirming, setIsConfirming] = useState(false);

  const filteredCandidates = candidates.filter(c => c.constituency === voterConstituency);

  const handleCastVote = () => {
    if (selectedId) {
      onVote(selectedId);
    }
  };

  if (isConfirming && selectedId) {
    const candidate = candidates.find(c => c.id === selectedId)!;
    return (
      <div className="max-w-2xl mx-auto bg-white rounded-3xl p-8 shadow-xl border-4 border-[#FF9933]">
        <h2 className="text-3xl font-extrabold text-center mb-6 text-gray-800">Final Confirmation</h2>
        <div className="bg-gray-50 rounded-2xl p-6 mb-8 text-center">
          <div className="text-6xl mb-4">{candidate.symbol}</div>
          <p className="text-gray-500 text-sm uppercase tracking-widest">You have selected</p>
          <h3 className="text-2xl font-bold text-[#000080] mt-1">{candidate.name}</h3>
          <p className="text-green-700 font-semibold mt-1">{candidate.party}</p>
        </div>

        <div className="flex items-start space-x-3 bg-amber-50 p-4 rounded-lg mb-8">
          <AlertCircle className="text-amber-500 mt-1 flex-shrink-0" size={20} />
          <p className="text-sm text-amber-800 italic">
            Disclaimer: Once cast, your vote cannot be changed or revoked. This action is irreversible as per EC norms.
          </p>
        </div>

        <div className="grid grid-cols-2 gap-4">
          <button
            onClick={() => setIsConfirming(false)}
            className="py-4 rounded-xl font-bold text-gray-600 bg-gray-100 hover:bg-gray-200 transition-colors"
          >
            Go Back
          </button>
          <button
            onClick={handleCastVote}
            className="py-4 rounded-xl font-bold text-white bg-[#138808] hover:bg-[#0f6b06] shadow-lg shadow-green-200 transition-all transform hover:scale-[1.02]"
          >
            CONFIRM VOTE
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto">
      <div className="mb-8 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold text-gray-800">Digital Ballot Box</h2>
          <p className="text-gray-500">Constituency: <span className="font-semibold text-[#000080]">{voterConstituency}</span></p>
        </div>
        <div className="bg-[#FF9933]/10 text-[#FF9933] px-4 py-2 rounded-full font-bold flex items-center space-x-2">
          <span className="relative flex h-3 w-3">
            <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-orange-400 opacity-75"></span>
            <span className="relative inline-flex rounded-full h-3 w-3 bg-orange-500"></span>
          </span>
          <span>Live Election Period</span>
        </div>
      </div>

      <div className="grid grid-cols-1 gap-4">
        {filteredCandidates.map((candidate) => (
          <div
            key={candidate.id}
            onClick={() => setSelectedId(candidate.id)}
            className={`cursor-pointer group relative bg-white p-5 rounded-2xl border-2 transition-all flex items-center justify-between hover:shadow-md ${
              selectedId === candidate.id 
                ? 'border-[#FF9933] bg-orange-50/30' 
                : 'border-gray-100 hover:border-gray-200'
            }`}
          >
            <div className="flex items-center space-x-6">
              <div className="w-16 h-16 bg-gray-50 rounded-xl flex items-center justify-center text-3xl group-hover:scale-110 transition-transform">
                {candidate.symbol}
              </div>
              <div>
                <h3 className="text-xl font-bold text-gray-800">{candidate.name}</h3>
                <p className="text-[#138808] font-medium text-sm">{candidate.party}</p>
                <p className="text-gray-400 text-xs mt-1 max-w-md hidden md:block">{candidate.description}</p>
              </div>
            </div>

            <div className="flex items-center space-x-4">
              {selectedId === candidate.id && (
                <CheckCircle2 className="text-[#138808]" size={28} />
              )}
              <div className={`w-8 h-8 rounded-full border-2 flex items-center justify-center ${
                selectedId === candidate.id ? 'bg-[#FF9933] border-[#FF9933]' : 'border-gray-300'
              }`}>
                 {selectedId === candidate.id && <div className="w-3 h-3 bg-white rounded-full"></div>}
              </div>
            </div>
          </div>
        ))}
      </div>

      <div className="mt-10 flex justify-center">
        <button
          disabled={!selectedId}
          onClick={() => setIsConfirming(true)}
          className={`px-12 py-4 rounded-full font-bold text-lg transition-all shadow-xl ${
            selectedId 
              ? 'bg-[#000080] text-white hover:bg-blue-900 transform hover:scale-105 active:scale-95' 
              : 'bg-gray-200 text-gray-400 cursor-not-allowed'
          }`}
        >
          CAST SECURE VOTE
        </button>
      </div>

      <p className="mt-6 text-center text-xs text-gray-400 italic">
        This portal uses E2E verifiable encryption to ensure your vote is counted correctly.
      </p>
    </div>
  );
};

export default VotingBallot;

import React from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';
import { APP_THEME } from '../constants';

interface ResultsDashboardProps {
  data: { name: string; votes: number; party: string }[];
}

const ResultsDashboard: React.FC<ResultsDashboardProps> = ({ data }) => {
  const COLORS = ['#FF9933', '#138808', '#000080', '#FFCC00', '#666666'];

  return (
    <div className="space-y-8 animate-fadeIn">
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Bar Chart */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
          <h3 className="text-lg font-bold text-gray-800 mb-6">Vote Count by Candidate</h3>
          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={data}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} />
                <XAxis dataKey="name" />
                <YAxis />
                <Tooltip 
                  cursor={{fill: 'transparent'}}
                  contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                />
                <Bar dataKey="votes" radius={[4, 4, 0, 0]}>
                  {data.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Pie Chart */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
          <h3 className="text-lg font-bold text-gray-800 mb-6">Vote Share Distribution</h3>
          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={data}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="votes"
                >
                  {data.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <div className="grid grid-cols-2 gap-2 mt-4">
            {data.map((item, idx) => (
              <div key={item.name} className="flex items-center space-x-2">
                <div className="w-3 h-3 rounded-full" style={{ backgroundColor: COLORS[idx % COLORS.length] }}></div>
                <span className="text-xs text-gray-600 truncate">{item.name} ({item.party})</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Leaderboard */}
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
        <h3 className="text-lg font-bold text-gray-800 mb-4">Detailed Tally</h3>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="text-xs font-bold text-gray-400 uppercase tracking-widest border-b">
                <th className="pb-3">Candidate</th>
                <th className="pb-3">Party</th>
                <th className="pb-3 text-right">Votes</th>
                <th className="pb-3 text-right">Progress</th>
              </tr>
            </thead>
            <tbody className="divide-y">
              {data.sort((a, b) => b.votes - a.votes).map((item) => {
                const total = data.reduce((acc, curr) => acc + curr.votes, 0);
                const percentage = ((item.votes / total) * 100).toFixed(1);
                return (
                  <tr key={item.name} className="hover:bg-gray-50 transition-colors">
                    <td className="py-4 font-semibold text-gray-800">{item.name}</td>
                    <td className="py-4 text-sm text-gray-600">{item.party}</td>
                    <td className="py-4 text-right font-mono font-bold">{item.votes.toLocaleString()}</td>
                    <td className="py-4 text-right">
                      <div className="flex items-center justify-end space-x-2">
                        <div className="w-24 h-2 bg-gray-100 rounded-full overflow-hidden">
                          <div 
                            className="h-full bg-[#138808]" 
                            style={{ width: `${percentage}%` }}
                          ></div>
                        </div>
                        <span className="text-xs font-bold text-gray-500 w-10">{percentage}%</span>
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

