  const [currentAdmin, setCurrentAdmin] = useState<Admin | null>(null);
  const [results, setResults] = useState<{ name: string; votes: number; party: string }[]>([]);

  // Initialize some mock results
  useEffect(() => {
    const initialResults = CANDIDATES.map(c => ({
      name: c.name,
      party: c.party,
      votes: Math.floor(Math.random() * 50000) + 10000
    }));
    setResults(initialResults);
  }, []);

  const handleLogin = (epic: string, pin: string) => {
    // Mock voter authentication
