      epicNumber: epic,
      name: "Rahul Sharma",
      constituency: "New Delhi",
      hasVoted: false,
      isVerified: true
    };
    setCurrentUser(mockVoter);
    setCurrentAdmin(null);
    setCurrentView('DASHBOARD');
  };

  const handleAdminLogin = (user: string, pass: string) => {
