  };

  const handleLogout = () => {
    setCurrentUser(null);
    setCurrentAdmin(null);
    setCurrentView('LOGIN');
  };

  const handleCastVote = (candidateId: string) => {
    if (currentUser) {
      const candidate = CANDIDATES.find(c => c.id === candidateId);
      if (candidate) {
        setResults(prev => prev.map(r => 
          r.name === candidate.name ? { ...r, votes: r.votes + 1 } : r
        ));
      }

      setCurrentUser({ ...currentUser, hasVoted: true });
      setCurrentView('RESULTS');
      alert('Vote cast successfully! Thank you for participating in the world\'s largest democracy.');
    }
  };

  // Routing Logic
  if (currentView === 'LOGIN') {
    return <Login onLogin={handleLogin} onAdminPortal={() => setCurrentView('ADMIN_LOGIN')} />;
  }

  if (currentView === 'ADMIN_LOGIN') {
    return <AdminLogin onLogin={handleAdminLogin} onBack={() => setCurrentView('LOGIN')} />;
  }

