import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Login from './components/Login';
import AdminLogin from './components/AdminLogin';
import AdminDashboard from './components/AdminDashboard';
import VotingBallot from './components/VotingBallot';
import ResultsDashboard from './components/ResultsDashboard';
import AIAssistant from './components/AIAssistant';
import { ViewState, Voter, Candidate, Admin, AuditLog } from './types';
import { CANDIDATES as INITIAL_CANDIDATES } from './constants';
import { CheckCircle, Info, Vote, History, MapPin, Award, Sparkles } from 'lucide-react';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>('LOGIN');
  const [currentUser, setCurrentUser] = useState<Voter | null>(null);
  const [currentAdmin, setCurrentAdmin] = useState<Admin | null>(null);
  const [candidates, setCandidates] = useState<Candidate[]>(INITIAL_CANDIDATES);
  const [results, setResults] = useState<{ name: string; votes: number; party: string }[]>([]);
  const [logs, setLogs] = useState<AuditLog[]>([
    { id: '1', timestamp: new Date().toLocaleTimeString(), action: 'SYSTEM_BOOT', details: 'BharatVote Core Engine initialized.', severity: 'info' },
    { id: '2', timestamp: new Date().toLocaleTimeString(), action: 'SECURITY', details: 'Encryption keys rotated successfully.', severity: 'info' }
  ]);

  // Initialize results whenever candidates change
  useEffect(() => {
    setResults(prevResults => {
      return candidates.map(c => {
        const existing = prevResults.find(r => r.name === c.name);
        return existing || {
          name: c.name,
          party: c.party,
          votes: Math.floor(Math.random() * 5000) + 100 // Seed some random activity
        };
      });
    });
  }, [candidates]);

  const addLog = (action: string, details: string, severity: 'info' | 'warning' | 'critical' = 'info') => {
    const newLog: AuditLog = {
      id: Math.random().toString(36).substr(2, 9),
      timestamp: new Date().toLocaleTimeString(),
      action,
      details,
      severity
    };
    setLogs(prev => [newLog, ...prev].slice(0, 50));
  };

  const handleLogin = (epic: string, pin: string) => {
    const mockVoter: Voter = {
      epicNumber: epic,
      name: "Rahul Sharma",
      constituency: "New Delhi",
      hasVoted: false,
      isVerified: true
    };
    setCurrentUser(mockVoter);
    setCurrentAdmin(null);
    setCurrentView('DASHBOARD');
    addLog('VOTER_AUTH', `EPIC ${epic} authenticated from New Delhi node.`, 'info');
  };

  const handleAdminLogin = (user: string, pass: string) => {
    const mockAdmin: Admin = {
      id: 'admin_1',
      username: user,
      role: 'SYSTEM_ADMIN'
    };
    setCurrentAdmin(mockAdmin);
    setCurrentUser(null);
    setCurrentView('ADMIN_DASHBOARD');
    addLog('ADMIN_AUTH', `Official session started for user: ${user}`, 'warning');
  };

  const handleLogout = () => {
    const name = currentAdmin ? currentAdmin.username : (currentUser ? currentUser.name : 'Unknown');
    addLog('LOGOUT', `Session terminated for ${name}`, 'info');
    setCurrentUser(null);
    setCurrentAdmin(null);
    setCurrentView('LOGIN');
  };

  const handleCastVote = (candidateId: string) => {
    if (currentUser) {
      const candidate = candidates.find(c => c.id === candidateId);
      if (candidate) {
        setResults(prev => prev.map(r => 
          r.name === candidate.name ? { ...r, votes: r.votes + 1 } : r
        ));
        addLog('BALLOT_CAST', `Anonymous vote recorded for ${candidate.constituency} region.`, 'info');
      }

      setCurrentUser({ ...currentUser, hasVoted: true });
      setCurrentView('RESULTS');
    }
  };

  const handleAddCandidate = (newCandidate: Candidate) => {
    setCandidates(prev => [...prev, newCandidate]);
    addLog('CONFIG_CHANGE', `New candidate added: ${newCandidate.name} (${newCandidate.party})`, 'warning');
  };

  const handleDeleteCandidate = (id: string) => {
    const candidate = candidates.find(c => c.id === id);
    setCandidates(prev => prev.filter(c => c.id !== id));
    if (candidate) {
      addLog('CONFIG_CHANGE', `Candidate removed from registry: ${candidate.name}`, 'critical');
    }
  };

  if (currentView === 'LOGIN') {
    return <Login onLogin={handleLogin} onAdminPortal={() => setCurrentView('ADMIN_LOGIN')} />;
  }

  if (currentView === 'ADMIN_LOGIN') {
    return <AdminLogin onLogin={handleAdminLogin} onBack={() => setCurrentView('LOGIN')} />;
  }

  return (
    <Layout 
      currentView={currentView} 
      setView={setCurrentView} 
      voterName={currentUser?.name}
      onLogout={handleLogout}
      isAdmin={!!currentAdmin}
    >
      {currentView === 'DASHBOARD' && currentUser && (
        <div className="space-y-8 animate-fadeIn">
          <div className="bg-white p-8 rounded-3xl shadow-sm border border-gray-100 relative overflow-hidden">
