                  <div>
                    <p className="text-xs text-gray-400 uppercase font-bold tracking-wider">Status</p>
                    <p className={`text-lg font-bold ${currentUser.hasVoted ? 'text-green-600' : 'text-orange-600'}`}>
                      {currentUser.hasVoted ? 'Voted' : 'Eligible'}
                    </p>
                  </div>
                </div>

                <div className="bg-gray-50 p-6 rounded-2xl flex items-center space-x-4">
                  <div className="p-3 bg-purple-100 text-purple-600 rounded-xl">
                    <Award size={24} />
                  </div>
                  <div>
                    <p className="text-xs text-gray-400 uppercase font-bold tracking-wider">Verified Identity</p>
                    <p className="text-lg font-bold text-gray-800">{currentUser.epicNumber}</p>
                  </div>
                </div>
              </div>
            </div>
          </div>

          {!currentUser.hasVoted ? (
            <div className="bg-[#138808] p-8 rounded-3xl text-white shadow-xl shadow-green-100 flex flex-col md:flex-row items-center justify-between gap-6">
              <div className="flex items-center space-x-6">
                <div className="hidden sm:flex w-20 h-20 bg-white/20 rounded-full items-center justify-center border-4 border-white/30">
                  <Vote size={40} className="text-white" />
                </div>
                <div>
                  <h3 className="text-2xl font-bold">Cast Your Vote Now</h3>
                  <p className="opacity-90 max-w-md mt-1">Select your candidate for the {currentUser.constituency} legislative seat. Voting ends in 4 hours.</p>
                </div>
              </div>
              <button 
