                  <h3 className="text-2xl font-bold text-blue-900">Thank you for voting!</h3>
                  <p className="text-blue-700/80 mt-1">You have successfully participated in the current election cycle. View real-time results below.</p>
                </div>
              </div>
              <button 
                onClick={() => setCurrentView('RESULTS')}
                className="bg-blue-600 text-white px-8 py-4 rounded-full font-bold text-lg hover:bg-blue-700 transition-all shadow-lg"
