export default App;

import React, { useState } from 'react';
import { ShieldCheck, User, Lock, ArrowRight, Settings, ShieldAlert, Fingerprint } from 'lucide-react';

interface LoginProps {
  onVoterLogin: (epic: string, pin: string) => void;
  onAdminLogin: (user: string, pass: string) => void;
}

const Login: React.FC<LoginProps> = ({ onVoterLogin, onAdminLogin }) => {
  const [mode, setMode] = useState<'VOTER' | 'ADMIN'>('VOTER');
  const [voterData, setVoterData] = useState({ epic: '', pin: '' });
  const [adminData, setAdminData] = useState({ user: '', pass: '' });
  const [error, setError] = useState('');

  const handleVoterSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (voterData.epic.length < 5 || voterData.pin.length < 4) {
      setError('Please enter valid EPIC Number and Security PIN');
      return;
    }
    onVoterLogin(voterData.epic, voterData.pin);
  };

  const handleAdminSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminData.user === 'admin' && adminData.pass === 'admin123') {
      onAdminLogin(adminData.user, adminData.pass);
    } else {
      setError('Invalid official credentials');
    }
  };

  return (
    <div className={`min-h-screen flex items-center justify-center p-4 transition-colors duration-500 ${mode === 'VOTER' ? 'gradient-bg' : 'bg-slate-900'}`}>
