                mode === 'VOTER' ? 'bg-[#138808] hover:bg-[#0f6e06]' : 'bg-[#000080] hover:bg-blue-900'
              }`}
            >
              <span>{mode === 'VOTER' ? 'Authorize & Enter' : 'Access Command Center'}</span>
              <ArrowRight size={20} />
            </button>
          </form>

          {mode === 'VOTER' && (
            <div className="mt-8 pt-6 border-t border-gray-100">
              <p className="text-center text-xs text-gray-400 uppercase tracking-widest font-semibold mb-4">Secured Verification</p>
              <div className="grid grid-cols-3 gap-4">
                <div className="flex flex-col items-center opacity-40 grayscale">
                  <div className="w-10 h-10 bg-gray-100 rounded-full flex items-center justify-center mb-1">☝️</div>
                  <span className="text-[10px]">Biometric</span>
                </div>
                <div className="flex flex-col items-center opacity-40 grayscale">
                  <div className="w-10 h-10 bg-gray-100 rounded-full flex items-center justify-center mb-1">📷</div>
